class Solution {
    public char kthCharacter(long k, int[] operations) {
        String word = "";
        for (int operation : operations) {
            if (operation == 0) {
                word += word;
            } else if (operation == 1) {
                StringBuilder sb = new StringBuilder(word);
                for (int i = 0; i < k; i++) {
                    char nextChar = (char) ((char) word.charAt(word.length() - 1) + 1);
                    sb.setCharAt(word.length() - 1, nextChar);
                }
                word = sb.toString();
            }
        }
        return word.charAt(k - 1);
    }
}
```

